import{_ as e,E as o}from"./app.a050b316.js";var t="/images/guide/platform/pr.png",r="/images/guide/platform/approvepr.png",n="/images/guide/platform/TAG.png",s="/images/guide/platform/TC.png";const a={},i=o('<h1 id="version-control" tabindex="-1"><a class="header-anchor" href="#version-control" aria-hidden="true">#</a> Version control</h1><p>This is how we manage and track changes to software code. A good example of version control is <a href="https://git-scm.com/" target="_blank" rel="noopener noreferrer">git</a>. Framely version control is modeled after git. Others can&#39;t see your branch, so you have to merge to master so that others can view the master version. Version control helps members collaborate in building the chatbot.</p><p><strong>1</strong>. Make sure that you have <strong>committed</strong> the changes on <strong>EN</strong> and then you should be back to <strong>STRUCT</strong></p><p><strong>2</strong>. <em>Click</em> on <strong>version</strong> on the <strong>SideMenu</strong></p><p><strong>3</strong>. <em>Click</em> on <strong>+ Pull Request</strong> and you should be able to see your commit:</p><blockquote><p>Pull request is used to indicate that you want to merge to master</p></blockquote><p><img src="'+t+'" alt="pr"></p><p><strong>4</strong>. <em>Click</em> on the item and drawer should slide in and click <strong>Approve</strong> This is the review stage that can be done by your peers. For our case, we will just approve.</p><p><img src="'+r+'" alt="prapprove"></p><p><strong>5</strong>. <em>Click</em> on merge when the next drawer slides in. This should pop a modal where you enter version tag and <em>click</em><strong>Save</strong> . The changes are merged into master.</p><p><img src="'+n+'" alt="tag"></p><p>Collaboration is encouraged on the Framely platform. This is through you as an owner, inviting other people to be members of your organisation. You can also manage collaborators. We will discuss how to do that in a few steps:</p><blockquote><p>Note that some of the collaboration flow actions are based on our flexible <a href="/pricing">plans</a>.</p></blockquote><h4 id="how-to-invite-collaborators" tabindex="-1"><a class="header-anchor" href="#how-to-invite-collaborators" aria-hidden="true">#</a> How to invite collaborators</h4><p><strong>1</strong>. <em>Click</em> on the <strong>settings</strong> menulink to move to the organisation settings.</p><p><strong>2</strong> <em>Click</em> on <strong>Team member</strong> tab to move to the new page.</p><p><strong>3</strong> <em>Click</em> on <strong>Add member</strong>.</p><p><img src="'+s+'" alt="add team member"></p><p>When you add a member, you can perform the following actions on them. This is how you as an owner can manage members.</p><ul><li><p>Set as owner</p></li><li><p>Convert member to collaborator(Member now can longer access internal projects).</p></li><li><p>Remove member</p></li></ul><p>Collaborators can make changes and make <strong>pull requests</strong>. This will be <strong>reviewed</strong>, <strong>approved</strong> and <strong>Merged</strong>. The reviewer can also close the pull request. Changes made by member are not visible on the master branch until they make a pull request.</p>',21);function l(m,g){return i}var c=e(a,[["render",l],["__file","versioncontrol.html.vue"]]);export{c as default};
